func solve(s string) int64 {
    n := len(s)
    prefix_L := make([]int, n+1)
    prefix_C := make([]int, n+1)
    for i := 1; i <= n; i++ {
        prefix_L[i] = prefix_L[i-1] + (s[i-1] == 'L')
        prefix_C[i] = prefix_C[i-1] + (s[i-1] == 'C')
    }

    suffix_T := make([]int, n+1)
    for i := n - 1; i >= 0; i-- {
        suffix_T[i] = suffix_T[i+1] + (s[i] == 'T')
    }

    original := 0
    for j := 0; j < n; j++ {
        if s[j] == 'C' {
            original += prefix_L[j] * suffix_T[j+1]
        }
    }

    sum_T_after_C := 0
    for j := 0; j < n; j++ {
        if s[j] == 'C' {
            sum_T_after_C += suffix_T[j+1]
        }
    }

    max_L_T := 0
    for i := 0; i <= n; i++ {
        current := prefix_L[i] * suffix_T[i]
        if current > max_L_T {
            max_L_T = current
        }
    }

    max_L_C := 0
    for i := 0; i <= n; i++ {
        current := prefix_L[i] * prefix_C[i]
        if current > max_L_C {
            max_L_C = current
        }
    }

    var max_increase int
    if sum_T_after_C > max_increase {
        max_increase = sum_T_after_C
    }
    if max_L_T > max_increase {
        max_increase = max_L_T
    }
    if max_L_C > max_increase {
        max_increase = max_L_C
    }

    return int64(original + max_increase)
}
